def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slide = prs.slides[6] if len(prs.slides) > 6 else None
    if slide is None:
        return "Slide 7 not found.", 0.0
    found = False
    for shape in slide.shapes:
        if not shape.has_text_frame:
            continue
        for paragraph in shape.text_frame.paragraphs:
            text = paragraph.text.strip().lower()
            if 'aquifer contamination' == text:
                found = True
            elif 'aquifer contamination' in text and paragraph.level == 1:
                found = True
            # Accept either a distinct bullet or part of a valid bullet
    if found:
        return "'Aquifer contamination' bullet found on Slide 7.", 1.0
    else:
        return "'Aquifer contamination' bullet not found on Slide 7.", 0.0

def compute_score() -> tuple[str, float]:
    # Find Slide 5 in the original and modified deck screenshots
    slide_number = 7
    orig_img = next((s.image_path for s in original_ppt_screenshots if s.slide_number == slide_number), None)
    mod_img = next((s.image_path for s in modified_ppt_screenshots if s.slide_number == slide_number), None)

    if not (orig_img and mod_img):
        return ("Slide 7 screenshots missing for before or after.", 0.0)

    prompt = (
        "You are given two images: a 'before' and 'after' screenshot of a PowerPoint slide for a modification task.\n"
        "Compare the 2 images and check if the bullet point 'Aquifer contamination' has been added under the Groundwater section.\n"
        "Respond only with YES or NO."
    )

    response = vlm_call(prompt, images=[orig_img, mod_img], temperature=0.0, max_tokens=5)
    response_lower = response.lower()

    if 'yes' in response_lower:
        return ("Bullet point 'Aquifer contamination' was added under the Groundwater section.", 1.0)
    elif 'no' in response_lower:
        return ("Bullet point 'Aquifer contamination' was not added under the Groundwater section.", 0.0)

def compute_score() -> tuple[str, float]:
    # Only slide 7 (slide_number=7) should be altered
    problematic_mods = []
    for (old, new) in ppt_diff.modified_slides:
        if old.slide_number != 7:
            # Check if nontrivial changes happened
            major = False
            # Check notes, title, number of elements (as proxy)
            if old.title != new.title or (old.notes or "") != (new.notes or "") or old.element_count != new.element_count:
                major = True
            if major:
                problematic_mods.append(old.slide_number)
    # Check for added/removed slides
    added = [s.slide_number for s in ppt_diff.added_slides if s.slide_number != 7]
    removed = [s.slide_number for s in ppt_diff.removed_slides if s.slide_number != 7]
    if problematic_mods or added or removed:
        return f"Slides other than 7 changed: modified={problematic_mods}, added={added}, removed={removed}.", 0.0
    return "No extraneous changes to other slides.", 1.0
